export default class DatePicker {
    constructor({ 
        element, 
        appendToBody = false,
        selectedDate = null, 
        minDate = null, 
        maxDate = null, 
        format = "yyyy-MM-dd",
        showAdjacentMonthDays = true,
        quickDateOptions = null,
        permissions = true
    }) {
        this._element = element;
        this._selectedDate = selectedDate ? new Date(selectedDate) : null;
        this._minDate = minDate ? new Date(minDate) : null;
        this._maxDate = maxDate ? new Date(maxDate) : null;
        this._format = format;
        this._showAdjacentMonthDays = showAdjacentMonthDays;
        this._currentMonth = this._selectedDate ? new Date(this._selectedDate) : new Date();
        this._isOpen = false;
        this._eventListeners = {};
        this._permissions = permissions;
        
        // Bind methods to preserve 'this' context
        this._toggleCalendarBound = this._toggleCalendar.bind(this);
        this.handleOutsideClickBound = (e) => {
            if (this._isOpen && !this._element.contains(e.target)) {
                this._closeCalendar();
            }
        };
        
        // Set default quick date options if none provided
        const today = new Date();
        if(quickDateOptions){
            this.quickDateOptions = quickDateOptions || [
                { label: "Today", date: new Date() },
                { label: "Tomorrow", date: new Date(today.getTime() + 24 * 60 * 60 * 1000) },
                { label: "In 4 days", date: new Date(today.getTime() + 4 * 24 * 60 * 60 * 1000) }
            ];
        }
        
        this.prefix = "f";
        this.staticClass = {
            container: `${this.prefix}-d-c`,
            input: `${this.prefix}-d-i`,
            calendar: `${this.prefix}-d-c`,
            header: `${this.prefix}-d-h`,
            days: `${this.prefix}-d-d`,  // This should be days, not day
            day: `${this.prefix}-d-da`   // This should be day, not days
        };
        
        // First render the elements
        this._render();
        // Then set up event listeners
        if(this._permissions){
            this._setupEventListeners();
        }
    }
    
    _render() {
        // Create a container div that will be placed after the element
        this.container = document.createElement("div");
        this.container.className = `${this.staticClass.container}-c`;
        
        // Set text content directly on the element
        if (this._selectedDate) {
            this._element.textContent = this._formatDate(this._selectedDate);
            this._element.setAttribute('value', this._selectedDate.toISOString());
        }
        
        // Insert container after the element
        if (this.appendToBody) {
            document.body.appendChild(this.container);
        } else {
            this._element.parentNode.insertBefore(this.container, this._element.nextSibling);
        }
        
        // Use the element directly as the input field
        this.inputField = this._element;
        this.inputField.classList.add("f--input","f--input--a");
        
        
    }
    
    _setupEventListeners() {
        this.inputField.addEventListener("click", () => this._toggleCalendar());
        
        // Handle click outside
        document.addEventListener("click", (e) => {
            if (this._isOpen && !this._element.contains(e.target)) {
                this._closeCalendar();
            }
        });
    }
    
    _toggleCalendar() {
        if (this._isOpen) {
            this._closeCalendar();
        } else {
            this._openCalendar();
        }
    }
    
    _openCalendar() {
        if (this.calendar) {
            this.calendar.remove();
        }
        
        this._createCalendar();
        this._isOpen = true;
        
        setTimeout(() => {
            if (this.calendar) {
                this.calendar.classList.add("fi");
            }
        }, 100);
    }
    
    _closeCalendar() {
        if (this.calendar) {
            this.calendar.classList.remove("fi");
            setTimeout(() => {
                if (this.calendar) {
                    this.calendar.remove();
                    this.calendar = null;
                }
            }, 100);
        }
        this._isOpen = false;
    }
    
    _createCalendar() {
        this.calendar = document.createElement("div");
        this.calendar.className = `${this.staticClass.calendar} fie`;
        
        // Create quick date picker section
        if(this.quickDateOptions){
            const quickDatePicker = document.createElement("div");
            quickDatePicker.className = `${this.prefix}-q-d-p`;
            
            // Create divs for each quick date option
            this.quickDateOptions.forEach(option => {
                const quickDateBtn = document.createElement("div");
                quickDateBtn.className = `${this.prefix}-q-d-b`;
                quickDateBtn.textContent = option.label;
                
                // Check if this option is selectable
                if (this._isDateSelectable(option.date)) {
                    quickDateBtn.addEventListener("click", () => {
                        this._selectDate(option.date);
                    });
                } else {
                    quickDateBtn.classList.add("disabled");
                }
                
                quickDatePicker.appendChild(quickDateBtn);
            });
            
            // Add quick date picker to calendar
            this.calendar.appendChild(quickDatePicker);
        }
        
        // Create header with month/year and navigation
        const header = document.createElement("div");
        header.className = this.staticClass.header;
        
        const prevBtn = document.createElement("div");
        prevBtn.innerHTML = "&#10094;";
        prevBtn.className = "p-m";
        prevBtn.addEventListener("click", (e) => {
            e.stopPropagation();
            this._prevMonth();
        });
        
        const nextBtn = document.createElement("div");
        nextBtn.innerHTML = "&#10095;";
        nextBtn.className = "n-m";
        nextBtn.addEventListener("click", (e) => {
            e.stopPropagation();
            this._nextMonth();
        });
        
        const monthYearText = document.createElement("span");
        monthYearText.textContent = this._formatMonthYear(this._currentMonth);
        
        header.appendChild(prevBtn);
        header.appendChild(monthYearText);
        header.appendChild(nextBtn);
        
        this.calendar.appendChild(header);
        
        // Create weekday headers
        const weekdays = ["Su", "Mo", "Tu", "We", "Th", "Fr", "Sa"];
        const daysContainer = document.createElement("div");
        daysContainer.className = this.staticClass.days;
        
        weekdays.forEach(day => {
            const dayEl = document.createElement("div");
            dayEl.className = "w";
            dayEl.textContent = day;
            daysContainer.appendChild(dayEl);
        });
        
        // Create calendar days
        this._renderCalendarDays(daysContainer);
        
        this.calendar.appendChild(daysContainer);
        this._element.appendChild(this.calendar);
    }
    
    _renderCalendarDays(container) {
        const year = this._currentMonth.getFullYear();
        const month = this._currentMonth.getMonth();
        
        const firstDay = new Date(year, month, 1);
        const lastDay = new Date(year, month + 1, 0);
        
        const firstDayOfWeek = firstDay.getDay();
        const daysInMonth = lastDay.getDate();
        
        // Previous month days
        if (firstDayOfWeek > 0) {
            const prevMonth = new Date(year, month, 0);
            const prevMonthDays = prevMonth.getDate();
            
            for (let i = 0; i < firstDayOfWeek; i++) {
                const dayEl = document.createElement("div");
                dayEl.className = `${this.staticClass.day} inactive disabled`;
                
                if (this._showAdjacentMonthDays) {
                    const day = prevMonthDays - firstDayOfWeek + i + 1;
                    dayEl.textContent = day;
                    
                    // Create date for previous month day
                    const prevMonthDate = new Date(year, month - 1, day);
                    
                    // We don't add click handlers for adjacent month days
                    // They are always disabled
                }
                
                container.appendChild(dayEl);
            }
        }
        
        // Current month days
        for (let i = 1; i <= daysInMonth; i++) {
            const dayEl = document.createElement("div");
            dayEl.className = this.staticClass.day;
            dayEl.textContent = i;
            
            const currentDate = new Date(year, month, i);
            
            // Check if date is selectable
            if (this._isDateSelectable(currentDate)) {
                // Check if this is the selected date
                if (this._selectedDate && 
                    currentDate.getDate() === this._selectedDate.getDate() &&
                    currentDate.getMonth() === this._selectedDate.getMonth() &&
                    currentDate.getFullYear() === this._selectedDate.getFullYear()) {
                    dayEl.classList.add("selected");
                }
                
                dayEl.addEventListener("click", () => this._selectDate(currentDate));
            } else {
                dayEl.classList.add("disabled");
            }
            
            container.appendChild(dayEl);
        }
        
        // Next month days - only to complete the last week
        const lastDayOfWeek = (firstDayOfWeek + daysInMonth - 1) % 7;
        const remainingDaysInWeek = lastDayOfWeek < 6 ? 6 - lastDayOfWeek : 0;
        
        for (let i = 1; i <= remainingDaysInWeek; i++) {
            const dayEl = document.createElement("div");
            dayEl.className = `${this.staticClass.day} inactive disabled`;
            
            if (this._showAdjacentMonthDays) {
                dayEl.textContent = i;
                
                // Create date for next month day
                const nextMonthDate = new Date(year, month + 1, i);
                
                // We don't add click handlers for adjacent month days
                // They are always disabled
            }
            
            container.appendChild(dayEl);
        }
    }
    
    _isDateSelectable(date) {
        if (this._minDate && date < this._minDate) return false;
        if (this._maxDate && date > this._maxDate) return false;
        return true;
    }
    
    _selectDate(date) {
        this._selectedDate = date;
        this._element.textContent = this._formatDate(date);
        this._element.setAttribute('value', date.toISOString());
        
        this._closeCalendar();
        
        // Create an enhanced data object with multiple formats
        const eventData = {
            date: this._selectedDate,
            formatted: this._formatDate(this._selectedDate),
            iso: this._selectedDate.toISOString()
        };
        
        // Dispatch event with enhanced data
        this._dispatchEvent('change', eventData);
    }
    
    _prevMonth() {
        this._currentMonth.setMonth(this._currentMonth.getMonth() - 1);
        this._updateCalendar();
    }
    
    _nextMonth() {
        this._currentMonth.setMonth(this._currentMonth.getMonth() + 1);
        this._updateCalendar();
    }
    
    _updateCalendar() {
        // Remove the calendar without animation
        if (this.calendar) {
            this.calendar.remove();
            this.calendar = null;
        }
        
        // Create new calendar
        this._createCalendar();
        
        // Add fade-in class immediately without animation
        if (this.calendar) {
            this.calendar.classList.add("fi");
        }
    }
    
    _formatDate(date) {
        let formatted = this._format;
        
        const day = date.getDate();
        const month = date.getMonth() + 1;
        const year = date.getFullYear();
        
        const months = [
            'January', 'February', 'March', 'April', 'May', 'June',
            'July', 'August', 'September', 'October', 'November', 'December'
        ];
        
        const monthsShort = [
            'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun',
            'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'
        ];
        
        // Use regex with word boundaries to ensure exact pattern matching
        formatted = formatted.replace(/\bMMMM\b/g, months[date.getMonth()]);
        formatted = formatted.replace(/\bMMM\b/g, monthsShort[date.getMonth()]);
        formatted = formatted.replace(/\bMM\b/g, month.toString().padStart(2, '0'));
        formatted = formatted.replace(/\bM\b/g, month.toString());
        
        formatted = formatted.replace(/\bDD\b/g, day.toString().padStart(2, '0'));
        formatted = formatted.replace(/\bD\b/g, day.toString());
        
        formatted = formatted.replace(/\bYYYY\b/g, year.toString());
        formatted = formatted.replace(/\bYY\b/g, year.toString().slice(-2));
        
        return formatted;
    }
    
    _formatMonthYear(date) {
        const months = [
            'January', 'February', 'March', 'April', 'May', 'June',
            'July', 'August', 'September', 'October', 'November', 'December'
        ];
        return `${months[date.getMonth()]} ${date.getFullYear()}`;
    }
    
    _dispatchEvent(event, data) {
        if (this._eventListeners[event]) {
            this._eventListeners[event].forEach(callback => {
                callback({ type: event, data });
            });
        }
    }
    
}


window.DatePicker = DatePicker;