import DOM from './dom.js';
import Storage from './storage.js';

export default class Dragable {
    constructor({
        body,
        trigger,
        storageKey,
        type = 'free',  // 'free', 'snap', or 'fixed'
        initialPosition = { x: 0, y: 0 },
        allowDragOn = null,
        permissions = 'edit',
        offset = {
            top: 0,
            bottom: 0,
            left: 0,
            right: 0,
        },
        dragDelay = 250
    }) {
        this._dom = new DOM();
        this._storage = new Storage();
        this._body = this._dom.getOne(body);
        this._trigger = this._dom.getOne(trigger);
        this._storageKey = storageKey;
        this._type = type;
        this._initialPosition = initialPosition;
        this._allowDragOn = allowDragOn;
        this._offset = offset;
        this._dragDelay = dragDelay;
        this._permissions = permissions;

        this._mouseOffset = { x: 0, y: 0 };
        this._isDragging = false;
        this._hasDragged = false;
        this._dragStartTimer = null;
        this._lastPosition = { x: 0, y: 0 };
        
        // Event listeners
        this._eventListeners = {
            dragStart: [],
            dragMove: [],
            dragEnd: [],
            snap: []
        };

        if (!this._body) {
            console.error(`Dragable: body selector"${body}"not found`);
            return;
        }

        if (!this._trigger) {
            console.error(`Dragable: trigger selector"${trigger}"not found`);
            return;
        }

        // If type is fixed, don't set up drag events
        if (this._type !== 'fixed') {
            this._setupDrag();
        }
        
        this._restorePosition();
    }

    _setupDrag() {
        this._dom.setAttr(this._body, 'data-drag-body', 'true');
        this._dom.setAttr(this._trigger, 'draggable', 'false');


        if(this._permissions === 'view'){
            return;
        }
        
        this._trigger.addEventListener('mousedown', this._onMouseDown);
        document.addEventListener('mouseup', this._onMouseUp);
        document.addEventListener('mousemove', this._onMouseMove);
        
        // Add click handler to prevent clicks after drag
        this._trigger.addEventListener('click', this._onClick, true);
    }

    _onClick = (e) => {
        if (this._hasDragged) {
            e.stopPropagation();
            e.preventDefault();
            this._hasDragged = false;
        }
    };

    // Add event listener
    on(event, callback) {
        if (this._eventListeners[event]) {
            this._eventListeners[event].push(callback);
            return true;
        }
        return false;
    }

    // Remove event listener
    off(event, callback) {
        if (this._eventListeners[event]) {
            if (callback) {
                // Remove specific callback
                this._eventListeners[event] = this._eventListeners[event].filter(cb => cb !== callback);
            } else {
                // Remove all callbacks for this event
                this._eventListeners[event] = [];
            }
            return true;
        }
        return false;
    }

    // Trigger event
    _emitEvent(event, data) {
        if (this._eventListeners[event]) {
            this._eventListeners[event].forEach(callback => {
                callback(data);
            });
        }
    }

    _onMouseDown = (e) => {
        if (this._allowDragOn && !e.target.closest(this._allowDragOn)) {
            return;
        }

        this._hasDragged = false;
        
        // Store initial position for potential drag
        const bodyRect = this._body.getBoundingClientRect();
        this._mouseOffset.x = e.clientX - bodyRect.left;
        this._mouseOffset.y = e.clientY - bodyRect.top;
        this._startX = this._lastPosition.x || 0;
        this._startY = this._lastPosition.y || 0;
        this._startMouseX = e.clientX;
        this._startMouseY = e.clientY;

        // Add a pending class immediately
        this._dom.addClass(this._body, 'drag-pending');
        
        // Clear any existing timer
        if (this._dragStartTimer) {
            clearTimeout(this._dragStartTimer);
        }
        
        // Set timer for drag activation
        this._dragStartTimer = setTimeout(() => {
            e.preventDefault();
            this._isDragging = true;
            this._hasDragged = true;
            
            // Store original transition
            this._originalTransition = this._body.style.transition;
            
            // Remove transition during drag for smoother movement
            this._body.style.transition = 'none';
            
            // Remove pending class and add active drag classes
            this._dom.removeClass(this._body, 'drag-pending');
            this._dom.addClass(this._body, 'drag-start');
            this._dom.addClass(this._body, 'dragging');
            this._dom.addClass(this._trigger, 'dragging');
            this._dom.addClass(document.body, 'dragging');
            
            // Trigger dragStart event
            this._emitEvent('dragStart', {
                element: this._body,
                position: { ...this._lastPosition }
            });
        }, this._dragDelay);
    };

    _onMouseMove = (e) => {
        if (!this._isDragging) return;

        // Set hasDragged flag when actual movement occurs
        this._hasDragged = true;
        
        // Calculate movement delta from the start position
        const deltaX = e.clientX - this._startMouseX;
        const deltaY = e.clientY - this._startMouseY;
        
        // Apply delta to the starting position
        let x = this._startX + deltaX;
        let y = this._startY + deltaY;

        // Get body dimensions
        const bodyRect = this._body.getBoundingClientRect();
        
        // Get viewport dimensions
        const viewportWidth = window.innerWidth;
        const viewportHeight = window.innerHeight;
        
        // Apply offset constraints
        // Left boundary - account for left offset
        const leftBoundary = this._offset.left;
        if (x < leftBoundary) x = leftBoundary;
        
        // Right boundary - account for right offset
        const rightBoundary = viewportWidth - bodyRect.width - this._offset.right;
        if (x > rightBoundary) x = rightBoundary;
        
        // Top boundary - account for top offset
        const topBoundary = this._offset.top;
        if (y < topBoundary) y = topBoundary;
        
        // Bottom boundary - account for bottom offset
        const bottomBoundary = viewportHeight - bodyRect.height - this._offset.bottom;
        if (y > bottomBoundary) y = bottomBoundary;

        this._body.style.transform = `translate(${x}px, ${y}px)`;
        this._lastPosition = { x, y };
        
        // Trigger dragMove event
        this._emitEvent('dragMove', {
            element: this._body,
            position: { x, y },
            delta: { x: deltaX, y: deltaY }
        });
    };

    _onMouseUp = () => {
        // Clear the timer if drag hasn't started yet
        if (this._dragStartTimer) {
            clearTimeout(this._dragStartTimer);
            this._dragStartTimer = null;
        }
        
        // Remove the pending class if it exists
        this._dom.removeClass(this._body, 'drag-pending');
        
        if (!this._isDragging) return;
        this._isDragging = false;

        // Restore original transition
        this._body.style.transition = this._originalTransition || '';

        // Handle snap positioning if type is 'snap'
        if (this._type === 'snap') {
            this._snapToEdge();
        }

        // Remove drag classes
        this._dom.removeClass(this._body, 'drag-start');
        this._dom.removeClass(this._body, 'dragging');
        this._dom.removeClass(this._trigger, 'dragging');
        this._dom.removeClass(document.body, 'dragging');

        if (this._storageKey && this._lastPosition) {
            this._storage.set(this._storageKey, this._lastPosition);
        }
        
        // Trigger dragEnd event
        this._emitEvent('dragEnd', {
            element: this._body,
            position: { ...this._lastPosition },
            type: this._type
        });
    };

    _snapToEdge() {
        const viewportWidth = window.innerWidth;
        const bodyRect = this._body.getBoundingClientRect();
        const elementCenter = this._lastPosition.x + (bodyRect.width / 2);
        const viewportCenter = viewportWidth / 2;
        
        let newX;
        let snapPosition;
        
        // If element center is left of viewport center, snap to left
        if (elementCenter < viewportCenter) {
            newX = this._offset.left;
            snapPosition = 'left';
        } 
        // Otherwise snap to right
        else {
            newX = viewportWidth - bodyRect.width - this._offset.right;
            snapPosition = 'right';
        }
        
        // Apply smooth transition for snap
        this._body.style.transition = 'transform 0.2s ease';
        
        // Update position
        this._body.style.transform = `translate(${newX}px, ${this._lastPosition.y}px)`;
        this._lastPosition.x = newX;
        
        // Set data attribute for styling purposes
        this._dom.setAttr(this._body, 'data-snap', snapPosition);
        
        // Reset to original transition after animation completes
        setTimeout(() => {
            this._body.style.transition = this._originalTransition || '';
        }, 300);
        
        // Trigger snap event
        this._emitEvent('snap', {
            element: this._body,
            position: { x: newX, y: this._lastPosition.y },
            snapPosition: snapPosition
        });
    }

    _restorePosition() {
        const saved = this._storageKey ? this._storage.get(this._storageKey) : null;
        const position = saved || this._initialPosition;

        if (position) {
            const { x, y } = position;
            this._body.style.transform = `translate(${x}px, ${y}px)`;
            this._lastPosition = { x, y };
            
            // Set initial snap position if type is 'snap'
            if (this._type === 'snap') {
                // Determine which side of the screen the element is on
                const viewportWidth = window.innerWidth;
                const bodyRect = this._body.getBoundingClientRect();
                const elementCenter = x + (bodyRect.width / 2);
                const viewportCenter = viewportWidth / 2;
                
                // Set data-snap attribute based on position
                const snapPosition = elementCenter < viewportCenter ? 'left' : 'right';
                this._dom.setAttr(this._body, 'data-snap', snapPosition);
            }
        }
    }

    destroy() {
        // Clear any pending timers
        if (this._dragStartTimer) {
            clearTimeout(this._dragStartTimer);
        }
        
        this._trigger.removeEventListener('mousedown', this._onMouseDown);
        document.removeEventListener('mouseup', this._onMouseUp);
        document.removeEventListener('mousemove', this._onMouseMove);
        this._trigger.removeEventListener('click', this._onClick, true);
    }
}


window.Dragable = Dragable;
