import {
    _class,
    defaultValuesForm,
    FORM_EVENTS,
    FormInputJson,
    LoginInputJson
} from "../env.js";
import DatePicker from "./date-picker.js";
import DOM from "./dom.js";
import DropdownSelect from "./dropdown.js";
import FormValidation from "./form-validation.js";
import QueryHelper from "./query-helper.js";


export default class FormManager {
    constructor( state ) {
        this._state = state;
        this._dom = new DOM();
        
        this._validation = new FormValidation();

        this._query = new QueryHelper();


        this.defaultData = defaultValuesForm;
        this._assignees = this._state.assignees;
        this._priority = this._state.priority;
        this._status = this._state.status;



        this._formEvents = FORM_EVENTS;
        this.listeners = {};


        this.form = null;
        this.formType = null;
        this.taskId = null;
        this.task = null;

        
    }

    on(eventName, callback) {
        if (!this.listeners[eventName]) this.listeners[eventName] = [];
        this.listeners[eventName].push(callback);
    }

    off(eventName) {
        if (this.listeners[eventName]) {
            this.listeners[eventName] = [];
        }
    }

    trigger(eventName, data = null) {
        if (this.listeners[eventName]) {
            this.listeners[eventName].forEach((cb) => cb(data));
        }
    }

    _initListeners() {
        
        const submitBtn = this._dom.getOne('#f--submit', this.form);
        const cancelBtn = this._dom.getOne('#f--cancel', this.form);
        const formType = this._dom.getAttr(this.form, 'data-form-type');
        
        if (submitBtn) {
            this._dom.off(submitBtn, 'click', this._handleSubmit);
            

            if (formType === 'create') {
                this._handleSubmit = () => {
                    const formData = this._dom._getFormValue(this.form);
                    // console.table(formData);
                    // console.table(this.defaultData);
                    const isValid = this._validation.validate(this.form, formData, this.defaultData);
                    if(!isValid) return;
                    this.trigger(this._formEvents.fB, formData);
                    this.trigger(this._formEvents.fS, formData);
                };
            } else if (formType === 'update') {
                this._setupFormWatch(formType);
                this._dom.addClass(submitBtn, 'disabled');
                this._handleSubmit = () => {
                    const formData = this._dom._getFormValue(this.form);
                    formData.id = this.taskId;
                    const taskData = this._state.getTaskById(this.taskId);
                    if(taskData){
                        const isValid = this._validation.validate(this.form, formData, taskData);
                        if(!isValid) return;
                    }else{
                        console.error("Task not found");
                        return;
                    }
                    this.trigger(this._formEvents.fB, formData);
                    this.trigger(this._formEvents.fU, formData);
                };
            }
            
            this._dom.on(submitBtn, 'click', (e) => {
                e.preventDefault();
                this._handleSubmit();
            });
            
        }

        if (cancelBtn) {
            //cancelBtn.removeEventListener('click', this._handleCancel);
            this._dom.off(cancelBtn, 'click', this._handleCancel);
            this._handleCancel = () => {
                this.removeForm();
                this.trigger(this._formEvents.fCn);
            };
            // cancelBtn.addEventListener('click', this._handleCancel);
            this._dom.on(cancelBtn, 'click', this._handleCancel);
        }
    }

    _setupFormWatch( formType = "update") {
        console.log("Form Watch Setup");
        const fields = this._dom.get('[name]', this.form);
        let fieldData = this._dom._getFormValue(this.form);
        let taskData = this.defaultData;

        
        

        if(formType === "update"){
            taskData = this._state.getTaskById(this.taskId);
            const mousepos = {
                x: taskData.screeninfo.document.x,
                y: taskData.screeninfo.document.y
            }
            this._state.setState("mousePos", mousepos , 'form');    
        }
        
        
        // Add event listeners to each field
        fields.forEach(field => {

            const fieldName = this._dom.getAttr(field, 'name');
            const type = this._dom.getAttr(field, 'type');
            const event = type === "hidden" ? "change" : "input";

            const value = this._validation.getFieldValue(field);

            this._dom.on(field, event, () => {
                fieldData = this._dom._getFormValue(this.form);
                const isValid = this._validation.validate(this.form, fieldData, taskData);
                this.trigger(this._formEvents.fW, { fieldData, isValid, changedField: fieldName, element: field });
            });
            
        });

    }

    _collectFormData() {
        const data = {};
        if(this.formType === "update"){
            data.id = this.taskId;
        }
        const fields = this.form.querySelectorAll('[name]');
        fields.forEach((el) => {
            data[el.getAttribute('name')] = el.value;
        });
        return data;
    }





    #_create({
        id = '',
        className = ''
    }) {
        if (id === '' && className === '') {
            console.error("ID and className cannot be empty");
        }

        const element = document.createElement("div");
        if (id) {
            element.id = id;
        }
        if (className) {
            element.className = className;
        }

        return element;
    }

    loginForm(){
        const formHeader = this._createFormHeader("Login");
        const formInputBody = this.#_create({
            className: `${_class.form.formInputGroup}`
        });
        const formInputJsonRes = LoginInputJson({
            isEditing: true,
            defaultValues: {
                email: "isha@2cube.studio",
                password: "isha@1234",
                // email: "",
                // password: "",
            }
        });


        // formInputBody.innerHTML = Object.keys(formInputJsonRes).map((key) => {
        //     return this.#createInput(formInputJsonRes[key]);
        // }).join('');

        Object.keys(formInputJsonRes).map((key) => {
            //return this.#createInput(formInputJsonRes[key]);
            formInputBody.appendChild(this.#createInput(formInputJsonRes[key]));
        }).forEach((el) => {
            
        });


        // const formActionButton = this.#createFormActionButton({ submit: true, cancel: true });
        const formWrapper = this.#_create({
            id: "loginFormWrapper"
        });
        // const form = this.#_create({
        //     id: "loginForm",
        //     className: `${_class.form.wrapper}`
        // });

        const form = this._dom.create({
            tag: "form",
            attributes: {
                method: "post",
                action: "/"
            },
            id: "loginForm",
            className: `${_class.form.wrapper}`
        });

        
        // form.append(this._dom.Fragment(formHeader));
        form.append(formHeader);
        form.append(formInputBody);
        // form.append(formActionButton);
        form.append(this.#createFormActionButton({ submit: true, cancel: true }));
        form.setAttribute('data-form-type', 'login');
        form.classList.add('fi');
        formWrapper.appendChild(form);
        this.form = formWrapper;

        this._dom.append(document.body, formWrapper);
        const submitButton = this._dom.getOne('#f--submit', this.form)
        this._dom.on(submitButton, 'click', (e) => {
            e.preventDefault();
            const fields = this.form.querySelectorAll('[name]');
            const formData = {};
            fields.forEach((el) => {
                formData[el.getAttribute('name')] = el.value;
            });
            // this.trigger(this._formEvents.fL, formData );
            this.trigger(this._formEvents.fL, formData );
        });
        
        const cancelButton = this._dom.getOne('#f--cancel', this.form)
        this._dom.on(cancelButton, 'click', () => {
            this.removeForm();
            this.trigger(this._formEvents.fCn);
        });

        return this;
    }


    createForm({ viewportInfo, id, type, defaultValues = {}, reason = null}) {

        if (!id) { console.error("ID is required"); return; }
        if (!type) { console.error("Type is required"); return; }

        const not_allow_stages = [ 'form_created' ];

        if(not_allow_stages.includes(this._state.stage)){
            console.error(`Stage is ${this._state.stage}. it's not allowed`);
            return;
        }

        this.formType = type;

        

        let { role }  = this._state.getUserPermissions();
        let isEditable = true;

        /* Type = create Default value */
        let FormHeaderTitle = "New Bug Report";

        if(type === "update"){
            let _valuesFromState = this._state.getTaskById(defaultValues);
            
            this.taskId = _valuesFromState.id;
            this.task = _valuesFromState;
            defaultValues = {
                id: _valuesFromState.id,
                title: _valuesFromState.title,
                description: _valuesFromState.description,
                due_date: _valuesFromState.due_date,
                assigned_to: _valuesFromState.assigned_to[0],
                priority: _valuesFromState.priority,
                status: _valuesFromState.status,
            }
            FormHeaderTitle = "Update Bug Report";
            let { isSameUser } = this._state.getUserPermissions(this.task);
            this._query._setMkr(this.taskId , true);
            isEditable = role === 'admin' ? true : isSameUser;


            if(role === 'guest'){
                console.error("Guest user cannot update task");
                return;
            }
        }else {
            defaultValues = this.defaultData;
        }

        const NewForm = this._dom.createTree({
            tag: "form",
            id: id,
            className: `${_class.form.wrapper}`,
            attributes: {
                method: "post",
                action: "/",
                "data-form-type": type
            },
            children: [
                {
                    tag: "div",
                    className: `${_class.form.ft}`,
                    children: [
                        { tag: "div", inner: FormHeaderTitle }
                    ]
                },
            ]
        });


        const formInputGroup = this._dom.create({ className: `${_class.form.formInputGroup}`});
        const formInputJsonRes = FormInputJson({ isEditing: isEditable, defaultValues: defaultValues });
        Object.keys(formInputJsonRes).map((key) => {
            this._dom.append(formInputGroup, this.#createInput(formInputJsonRes[key]));
        });
        const formActionButtons = this.#createFormActionButton({ submit: true, cancel: true });
        this._dom.append(NewForm, [formInputGroup, formActionButtons]);
        this.form = NewForm;
                    
    
        this._dueDateCall('due_date',defaultValues.due_date,isEditable);
        this._assigneeCall('assigned_to',defaultValues.assigned_to,isEditable);
        this._priorityCall('priority',defaultValues.priority,isEditable);
        this._statusCall('status',defaultValues.status,isEditable);

        this._dom.append(document.body, this.form);
        this._initListeners();
        
        // setTimeout(() => {
        //     if (type === 'update') {
        //         const formData = this._collectFormData();
        //         const taskData = this._state.getTaskById(this.taskId);
        //         this.task = taskData;
        //         const isValid = this._validation.validate(this.form, formData, taskData);
                
        //         const submitBtn = this.form.querySelector('#f--submit');
        //         if (submitBtn && !isValid) {
        //             submitBtn.classList.add('disabled');
        //         }
        //     }
        // }, 250);

        this.trigger(this._formEvents.fC, { id: id, type: type, defaultValues, element: this.form });

        if(reason === 'marker_click'){
            this._state.setStage('form_view',`type:${type}>#createForm`);
        }else{
            this._state.setStage('form_created',`type:${type}>#createForm`);
        }
        
        if(type === "update"){
            this.form.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
        return this;
    }

    removeForm( reason = null ) {
        
        if(reason === 'marker_click'){
            this._state.setStage('marker_click',`type:${this.formType}>#removeForm`);
        }else{
            this._state.setStage('init',`type:${this.formType}>#removeForm`);
        }

        if(this._query._has('mkr')){
            this._query._removeMkr(true);
        }

        this.form.remove();
        this.form = null;
    }

    _createFormHeader(title) {
        // return `<div class="${_class.form.ft}">// <div class="">${title}</div>// </div>`;

        const formHeader = this._dom.createTree({
            tag: "div",
            className: `${_class.form.ft}`,
            children: [
                {
                    tag: "div",
                    inner: title
                }
            ]
        });

        return formHeader;
    }

    #createInput({
        tag = 'div',
        placeholder,
        contenteditable = false,
        name = null,
        value = '',
        label = '',
        type = 'text',
        className = ''
    }) {
        if (name === null) {
            console.error("Name is required");
        }

        const _className = type === 'hidden' ? '' : `${_class.form.input}`;
        contenteditable = type === 'hidden' ? false : contenteditable;

        // return `<div class="${_class.form.inputWrapper} ${className}">// <div class="${_class.form.label}">${label}</div>// <div // ${_className} // data-placeholder="${placeholder}"// contenteditable="${contenteditable}"// name="${name}"// type="${type}"// appearance="${type}"//>${value}</div>// </div>`;

        const InputWrapper = this._dom.create({
            tag: "div",
            className: `${_class.form.inputWrapper} ${className}`
        });

        const Input = this._dom.create({
            tag: tag,
            className: `${_className}`,
            attributes: {
                placeholder: placeholder,
                "contenteditable": contenteditable,
                "name": name,
                "type": name === 'password' ? 'password' : type,
                "appearance": type
            },
            inner: value
        });

        const inputLabel = this._dom.create({
            tag: "div",
            className: `${_class.form.label}`,
            inner: label
        });
        this._dom.append(InputWrapper, inputLabel);
        this._dom.append(InputWrapper, Input);

        return InputWrapper;


        
        
            
    }

    #createFormActionButton({
        submit = true,
        cancel = true
    }) {
       

        const actionButtonWrapper = this._dom.create({
            tag: "div",
            className: `${_class.form.actionButton.wrapper}`
        });

        if (submit) {
            const submitButton = this._dom.create({
                tag: "input",
                id: "f--submit",
                className: `${_class.form.actionButton.submit}`,
                inner: "Submit",
                attributes: {
                    type: "submit"
                }
            });
            this._dom.append(actionButtonWrapper, submitButton);
        }
        if (cancel) {
            const cancelButton = this._dom.create({
                tag: "input",
                id: "f--cancel",
                className: `${_class.form.actionButton.cancel}`,
                inner: "Cancel",
                attributes: {
                    type: "button"
                }
            });
            this._dom.append(actionButtonWrapper, cancelButton);
        }

        return actionButtonWrapper;
    }

    _dueDateCall( name , value = new Date() , permissions = 'edit' ){
        return new DatePicker({
            element:this.form.querySelector(`[name="${name}"]`),
            selectedDate: value,
            format: "DD-MMM-YYYY",
            showAdjacentMonthDays: true,
            permissions: permissions
        });
    }

    _assigneeCall( name , value , permissions = 'edit' ){
        return new DropdownSelect({
            element:this.form.querySelector(`[name="${name}"]`),
            data: this._assignees,
            key:"user_name",
            value:"user_id",
            type: "single",
            placeholder: "Select assignee",
            preselected: [value],
            permissions: permissions
        });
    }

    _priorityCall( name , value , permissions = 'edit' ){
        return new DropdownSelect({
            element:this.form.querySelector(`[name="${name}"]`),
            data: this._priority,
            type: "single",
            placeholder: "Select priority",
            preselected: [value],
            permissions: permissions
        });
    }

    _statusCall( name , value , permissions = 'edit' ){
        return new DropdownSelect({
            element:this.form.querySelector(`[name="${name}"]`),
            data: this._status,
            type: "single",
            placeholder: "Select status",
            preselected: [value],
            permissions: permissions
        });
    }



}


window.FormManager = FormManager;