    _attachClickListeners() {
        const elements = this._dom.get('.mkrClick');

        elements.forEach(el => {
            const taskId = el.getAttribute('data-mkr-id');
            const task = this._tasks.find(t => String(t.id) === String(taskId));
            if (!task) return;

            const isSamePage = this._query._getPageName(task.href) === this._query._getPageName(window.location.href);

            // Clone element to avoid duplicate listeners if needed
            const cleanEl = el.cloneNode(true);
            el.parentNode.replaceChild(cleanEl, el);

            if (isSamePage) {
                cleanEl.addEventListener('click', () => this._handleClick(task.id));
                
                // Check if this element already has a dragable instance
                if (!this._dragInstances) this._dragInstances = {};
                
                // Remove previous dragable instance if it exists
                if (this._dragInstances[task.id]) {
                    this._dragInstances[task.id].destroy();
                }
                
                // Create new dragable instance and store it
                this._dragInstances[task.id] = new Dragable({
                    body: `.mkr[data-mkr-id="${task.id}"]`,
                    trigger: `.mkr[data-mkr-id="${task.id}"]`,
                    storageKey: null,
                    type: 'free',
                    initialPosition: {
                        x: task.screeninfo.document.x,
                        y: task.screeninfo.document.y
                    }
                });
                
                this._dragInstances[task.id].on('dragEnd', async (data) => {
                    console.log('Drag Move', data.position);
                    const payload = {
                        "id": task.id,
                        "x": data.position.x,
                        "y": data.position.y
                    }
                    const res = await this._api.updateTaskPosition(payload);
                    console.log(res);
                });
            } else {
                cleanEl.addEventListener('click', e => this._handleTaskRedirectClick(e, task));
            }
        });
    }



    _handleClick(taskId) {
        if (['overlay', 'form_created'].includes(this._state.stage)) {
            console.warn(`Stage is ${this._state.stage}. Marker clicks not allowed`);
            return;
        }
        

        if (this._taskId === taskId) {
            this._clearActiveMarkers();
            this._taskId = null;
            this._state.setStage('marker_double_click', 'marker-double-click');
            this.clickCallback?.(taskId, true);
        } else {
            this._previousTaskId = this._taskId;
            this._taskId = taskId;
            this._clearActiveMarkers();
            this._dom.addClass(`[data-mkr-id="${taskId}"]`, 'active', true);
            this._state.setStage('marker_click', 'marker-click');
            this.clickCallback?.(taskId, false);
        }
    }

    // ===== Explorer =====
    toggleExplorer() {
        const explorer = document.querySelector("#explorer");
        if (explorer) {
            explorer.remove();
            this.priority = null;
            this.status = null;
        } else {
            this._renderExplorer();
        }
    }

    _renderExplorer() {
        const explorerHtml = ` <div class="f-gd f-px--n f-py--m"><div class="f-f--j"><div class="f-w--b">Bug Explorer</div></div></div><div class="filter-by f-px--n f-py--m f-f--j"><div class="priority"></div><div class="status"></div><div class="page-wise"></div></div><div class="f-px--m f-f taskList"></div>`;

        const explorer = this._dom.create({
            id: "explorer",
            className: "f-shadow f-explorer",
            inner: explorerHtml
        });
        this._dom.append(document.body, explorer);

        // Apply filters before rendering tasks
        this._updateTaskListUI(explorer);

        // Setup dropdowns with preselected values from URL parameters
        this._setupDropdown(explorer, '.priority', this._state.priority, 'Priority', 'priority', this.priority);
        this._setupDropdown(explorer, '.status', this._state.status, 'Status', 'status', this.status);
        this._setupDropdown(explorer, '.page-wise', this._pageNameList, 'Page', 'page', this.page);

        new Dragable({
            body: "#explorer",
            trigger: ".f-py--m",
            storageKey: 'explorer',
            type: 'snap',
            initialPosition: { x: 10, y: 70 },
            offset: { top: 10, bottom: 10, left: 70, right: 70 }
        });
    }

    // custom change event register and when dropdown change that time dispatch event
    


    _setupDropdown(container, selector, data, placeholder, filterKey) {
        const dropdown = new DropdownSelect({
            element: container.querySelector(selector),
            data,
            type: "single",
            style: "picker",
            placeholder,
            isClearable: true,
            prefetch: filterKey,
        });

        dropdown._element.addEventListener('change', (e) => {
            this[filterKey] = e.detail[0];
            this._updateTaskListUI(container);
            this.changeCallback?.(e.detail);
        });
    }

    _renderTaskCard(task) {
        const formattedDate = new Date(task.due_date).toLocaleDateString('en-US', {
            month: 'long', day: 'numeric', hour: 'numeric', minute: 'numeric'
        });

        const taskCard = this._dom.create({
            tag: "div",
            className: "f-w--f f-p--m f-e--task explorer-task mkrClick",
            attributes: {
                "data-mkr-id": task.id
            }
        });

        // <div class="f-w--f f-p--m f-e--task mkrClick" data-mkr-id="${task.id}">
        // </div>
        const html = ` <div class="f-f--j"><div class="f-s--s">${formattedDate}</div><div><div class="f--w">${task.page || 'index'}</div><div class="f--w ${task.priority}">${task.priority}</div></div></div><div class="f-pb--s f-s--m f-w--m">${task.title}</div><div class="f-pb--s f-s--m">${task.description}</div><div class="f-s--s f--w f--w--n low">${task.href}</div>`;

        taskCard.appendChild(this._dom.Fragment(html));
        taskCard.addEventListener('click', (e) => this._handleTaskRedirectClick(e, task));
        

        const taskListContainer = document.querySelector('.taskList');
        taskListContainer.appendChild(taskCard);
        // if (taskListContainer) taskListContainer.innerHTML += html;
    }

    _handleTaskRedirectClick(e, task) {
        const currentPage = this._all;  
        const taskPage = this._query._getAll(task.href);

        if (currentPage.pathname !== taskPage.pathname) {
            e.preventDefault();

            const confirmRedirect = window.confirm(
                `This task is from another page:\n\n${task.href}\n\nDo you want to navigate there?`
            );

            // Create a new QueryHelper instance with the task's href as base
            const taskQuery = new QueryHelper(task.href);
            
            // First remove any existing 'mkr' parameter
            if (taskQuery._has('mkr')) {
                taskQuery._remove('mkr');
            }
            
            // Add current query parameters from current page (except 'mkr')
            const _statick_key = ['page', 'priority', 'status'];
            _statick_key.forEach(key => {
                if(this[key]) {
                    taskQuery._add(key, this[key]);
                }else{
                    taskQuery._remove(key);
                }
            });
            
            
            // Add the task id as 'mkr' parameter
            taskQuery._add('mkr', task.id);
            
            // Get the final URL
            let href = taskQuery._toString();

            if (confirmRedirect) {
                window.location.href = href;
            }
        }
    }
    
